 2→import React from 'react';
 3→import { Recommendation, GeneratedSolution } from '../types';
 4→import { Zap, TrendingUp, Clock, CheckCircle2, Lock, Eye, Check } from 'lucide-react';
 5→
 6→interface Props {
 7→  rec: Recommendation;
 8→  cost: number;
 9→  onApply: (rec: Recommendation) => void;
10→  existingSolution?: GeneratedSolution | null;
11→  onView?: (solution: GeneratedSolution) => void;
12→}
13→
14→const RecommendationCard: React.FC<Props> = ({ rec, cost, onApply, existingSolution, onView }) => {
15→  const getBadgeColor = (p: string) => {
16→    switch(p) {
17→      case 'critical': return 'bg-red-500/20 text-red-300 border-red-500/30';
18→      case 'high': return 'bg-orange-500/20 text-orange-300 border-orange-500/30';
19→      case 'medium': return 'bg-amber-500/20 text-amber-300 border-amber-500/30';
20→      default: return 'bg-blue-500/20 text-blue-300 border-blue-500/30';
21→    }
22→  };
23→
24→  const handleButtonClick = (e: React.MouseEvent) => {
25→    e.stopPropagation();
26→    if (existingSolution && onView) {
27→      onView(existingSolution);
28→    } else {
29→      onApply(rec);
30→    }
31→  };
32→
33→  return (
34→    <div className={`glass-panel p-5 rounded-xl border transition-all border-white/10 hover:border-primary/30`}>
35→      <div className="flex justify-between items-start mb-3">
36→        <span className={`px-2 py-1 rounded text-xs font-semibold uppercase tracking-wider border ${getBadgeColor(rec.priority)}`}>
37→          {rec.priority}
38→        </span>
39→        <span className="text-xs text-gray-500">{rec.category}</span>
40→      </div>
41→      
42→      <h3 className="text-lg font-serif font-medium text-white mb-4">{rec.title}</h3>
43→      
44→      <div className={`p-3 rounded-lg mb-4 bg-white/5`}>
45→        <div className="flex items-start gap-2">
46→          {existingSolution ? (
47→             <Check className="text-emerald-400 shrink-0 mt-0.5" size={16} />
48→          ) : (
49→             <Zap className="text-accent shrink-0 mt-0.5" size={16} />
50→          )}
51→          <p className="text-sm text-gray-200">
52→            <span className={`font-semibold ${existingSolution ? 'text-emerald-400' : 'text-accent'}`}>
53→                {existingSolution ? 'Solution disponible :' : 'Action requise :'}
54→            </span> {rec.action}
55→          </p>
56→        </div>
57→      </div>
58→
59→      <div className="flex items-center justify-between text-xs text-gray-500 border-t border-white/10 pt-3">
60→        <div className="flex gap-4">
61→          <span className="flex items-center gap-1">
62→            <Clock size={12} /> Effort: <span className="text-gray-300 capitalize">{rec.effort}</span>
63→          </span>
64→          <span className="flex items-center gap-1">
65→            <TrendingUp size={12} /> Impact: <span className="text-gray-300 capitalize">{rec.impact}</span>
66→          </span>
67→        </div>
68→        
69→        <button 
70→            onClick={handleButtonClick}
71→            className={`
72→                px-3 py-1.5 rounded-lg flex items-center gap-2 font-medium transition-all group active:scale-95 transform border
73→                ${existingSolution 
74→                    ? 'bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border-emerald-500/20 hover:border-emerald-500/50' 
75→                    : 'bg-primary/10 hover:bg-primary/20 text-primary border-primary/20 hover:border-primary/50'}
76→            `}
77→        >
78→            {existingSolution ? <Eye size={12} className="fill-current" /> : <Zap size={12} className="fill-current" />}
79→            <span>{existingSolution ? 'Voir la solution' : `Générer Solution (-${cost})`}</span>
80→        </button>
81→      </div>
82→    </div>
83→  );
84→};
85→
86→export default RecommendationCard;
