  2→import React, { useState } from 'react';
  3→import { GeneratedSolution } from '../types';
  4→import { X, Copy, Check, Sparkles, Loader2, ClipboardList, Briefcase, ArrowRight, UserCheck, Download, FileCode } from 'lucide-react';
  5→
  6→interface Props {
  7→  isOpen: boolean;
  8→  onClose: () => void;
  9→  solution: GeneratedSolution | null;
 10→  isLoading: boolean;
 11→}
 12→
 13→const GenerationModal: React.FC<Props> = ({ isOpen, onClose, solution, isLoading }) => {
 14→  const [copied, setCopied] = useState(false);
 15→
 16→  if (!isOpen) return null;
 17→
 18→  const handleCopy = () => {
 19→    if (solution?.content) {
 20→      navigator.clipboard.writeText(solution.content);
 21→      setCopied(true);
 22→      setTimeout(() => setCopied(false), 2000);
 23→    }
 24→  };
 25→
 26→  const handleDownload = () => {
 27→    if (solution?.content) {
 28→        const extension = solution.language === 'html' ? 'html' : solution.language === 'json' ? 'json' : 'txt';
 29→        const blob = new Blob([solution.content], { type: 'text/plain' });
 30→        const url = URL.createObjectURL(blob);
 31→        const a = document.createElement('a');
 32→        a.href = url;
 33→        a.download = `solution_aeo.${extension}`;
 34→        document.body.appendChild(a);
 35→        a.click();
 36→        document.body.removeChild(a);
 37→        URL.revokeObjectURL(url);
 38→    }
 39→  };
 40→
 41→  const handleContactExpert = () => {
 42→    // In a real app, this would open a booking calendar or contact form
 43→    window.open('mailto:experts@citedby.ai?subject=Demande%20assistance%20Webmaster%20AEO', '_blank');
 44→  };
 45→
 46→  return (
 47→    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
 48→      {/* Backdrop */}
 49→      <div 
 50→        className="absolute inset-0 bg-black/80 backdrop-blur-sm transition-opacity"
 51→        onClick={onClose}
 52→      ></div>
 53→
 54→      {/* Modal Content */}
 55→      <div className="relative bg-[#0f1115] border border-white/10 rounded-2xl w-full max-w-5xl max-h-[90vh] flex flex-col shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
 56→        
 57→        {/* Header */}
 58→        <div className="p-6 border-b border-white/10 flex items-center justify-between bg-white/5">
 59→          <div className="flex items-center gap-3">
 60→            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-primary/20 to-secondary/20 flex items-center justify-center text-primary border border-white/5 shadow-inner">
 61→              <Sparkles size={20} />
 62→            </div>
 63→            <div>
 64→              <h3 className="text-lg font-serif font-bold text-white">
 65→                {isLoading ? 'Génération de la solution...' : solution?.title}
 66→              </h3>
 67→              {!isLoading && <p className="text-xs text-gray-400">Optimisation AEO générée par l'IA</p>}
 68→            </div>
 69→          </div>
 70→          <button 
 71→            onClick={onClose}
 72→            className="p-2 hover:bg-white/10 rounded-lg transition-colors text-gray-400 hover:text-white"
 73→          >
 74→            <X size={20} />
 75→          </button>
 76→        </div>
 77→
 78→        {/* Body */}
 79→        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#0a0a0f]">
 80→          {isLoading ? (
 81→            <div className="flex flex-col items-center justify-center h-full py-24 text-center space-y-6">
 82→              <div className="relative">
 83→                <Loader2 size={64} className="text-primary animate-spin" />
 84→                <div className="absolute inset-0 blur-xl bg-primary/20 rounded-full animate-pulse"></div>
 85→              </div>
 86→              <div className="space-y-2">
 87→                <p className="text-white font-medium text-lg animate-pulse">
 88→                  Analyse des critères de citation en cours...
 89→                </p>
 90→                <p className="text-sm text-gray-500">
 91→                  Rédaction du code et du guide d'implémentation pour débutant
 92→                </p>
 93→              </div>
 94→            </div>
 95→          ) : solution ? (
 96→            <div className="grid lg:grid-cols-12 h-full min-h-[500px]">
 97→              
 98→              {/* Left Column: The Code/Content (7 cols) */}
 99→              <div className="lg:col-span-7 p-6 border-b lg:border-b-0 lg:border-r border-white/10 flex flex-col">
100→                <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-lg text-sm text-blue-200 mb-6 leading-relaxed">
101→                  <span className="font-bold text-blue-300 block mb-1">Impact AEO :</span>
102→                  {solution.explanation}
103→                </div>
104→
105→                <div className="flex-1 flex flex-col">
106→                  <div className="flex justify-between items-center mb-3">
107→                    <span className="text-xs font-bold text-gray-400 uppercase tracking-wider flex items-center gap-2">
108→                      <FileCode size={14} className="text-gray-500" />
109→                      {solution.type === 'code' ? 'Fichiers Sources' : 'Contenu Optimisé'}
110→                      <span className="text-[10px] bg-white/10 px-1.5 py-0.5 rounded text-gray-500 font-normal normal-case">{solution.language}</span>
111→                    </span>
112→                    <div className="flex gap-2">
113→                        <button
114→                        onClick={handleDownload}
115→                        className="flex items-center gap-2 px-3 py-1.5 bg-white/5 hover:bg-white/10 rounded-md text-xs font-medium text-white transition-all border border-white/10 group"
116→                        title="Télécharger le fichier"
117→                        >
118→                        <Download size={14} className="group-hover:text-primary transition-colors" />
119→                        Télécharger
120→                        </button>
121→                        <button
122→                        onClick={handleCopy}
123→                        className="flex items-center gap-2 px-3 py-1.5 bg-white/5 hover:bg-white/10 rounded-md text-xs font-medium text-white transition-all border border-white/10 group"
124→                        >
125→                        {copied ? <Check size={14} className="text-emerald-400" /> : <Copy size={14} className="group-hover:text-primary transition-colors" />}
126→                        {copied ? 'Copié !' : 'Copier'}
127→                        </button>
128→                    </div>
129→                  </div>
130→                  
131→                  <div className="relative flex-1 min-h-[300px] bg-[#050508] rounded-xl border border-white/10 overflow-hidden shadow-inner group">
132→                    <pre className="absolute inset-0 p-5 overflow-auto text-sm font-mono leading-relaxed text-gray-300 custom-scrollbar">
133→                      <code>{solution.content}</code>
134→                    </pre>
135→                  </div>
136→                </div>
137→              </div>
138→
139→              {/* Right Column: Implementation Plan (5 cols) */}
140→              <div className="lg:col-span-5 p-6 bg-white/[0.02] flex flex-col h-full border-l border-black">
141→                <div className="mb-8">
142→                    <h4 className="text-lg font-serif font-bold mb-6 flex items-center gap-2 text-white">
143→                    <ClipboardList size={20} className="text-primary" />
144→                    Guide d'installation (Débutant)
145→                    </h4>
146→                    
147→                    <div className="space-y-0">
148→                    {solution.implementationSteps.map((step, idx) => (
149→                        <div key={idx} className="flex gap-4 pb-6 last:pb-0 relative group">
150→                            {/* Vertical Line */}
151→                            {idx !== solution.implementationSteps.length - 1 && (
152→                                <div className="absolute left-[11px] top-8 bottom-0 w-px bg-white/10 group-hover:bg-white/20 transition-colors"></div>
153→                            )}
154→                            
155→                            <div className="w-6 h-6 rounded-full bg-[#1a1d24] border border-white/20 flex items-center justify-center text-xs font-bold shrink-0 mt-0.5 z-10 text-gray-400 group-hover:text-primary group-hover:border-primary/50 transition-colors shadow-lg">
156→                                {idx + 1}
157→                            </div>
158→                            <p className="text-sm text-gray-300 leading-relaxed pt-0.5 group-hover:text-gray-100 transition-colors">{step}</p>
159→                        </div>
160→                    ))}
161→                    </div>
162→                </div>
163→
164→                <div className="mt-auto pt-6 border-t border-white/10">
165→                   <div className="bg-gradient-to-br from-white/5 to-white/[0.02] p-5 rounded-xl border border-white/10 hover:border-primary/30 transition-all group">
166→                        <div className="flex items-center gap-3 mb-3">
167→                            <div className="w-8 h-8 rounded-full bg-accent/20 flex items-center justify-center text-accent">
168→                                <Briefcase size={16} />
169→                            </div>
170→                            <h5 className="font-bold text-white text-sm">Déléguer cette tâche ?</h5>
171→                        </div>
172→                        <p className="text-xs text-gray-400 mb-4 leading-relaxed">
173→                            Envoyez ce guide et les fichiers à votre webmaster ou demandez l'assistance d'un expert certifié AEO.
174→                        </p>
175→                        <button 
176→                            onClick={handleContactExpert}
177→                            className="w-full py-2.5 bg-white hover:bg-gray-200 text-black font-bold rounded-lg transition-colors flex items-center justify-center gap-2 text-xs uppercase tracking-wide shadow-lg transform active:scale-95"
178→                        >
179→                            <UserCheck size={14} />
180→                            Trouver un Webmaster
181→                        </button>
182→                   </div>
183→                </div>
184→              </div>
185→
186→            </div>
187→          ) : null}
188→        </div>
189→      </div>
190→    </div>
191→  );
192→};
193→
194→export default GenerationModal;
