  1→import React, { useState, useEffect } from 'react';
  2→import { Project, SourceOfTruthData } from '../types';
  3→import { LLM_TRUTH_TEMPLATES } from '../services/llm_templates';
  4→import { X, FileText, Download, Copy, Sparkles, Check, Plus, Trash2, Building2, MapPin, Calendar } from 'lucide-react';
  5→
  6→interface Props {
  7→  isOpen: boolean;
  8→  onClose: () => void;
  9→  project: Project | null;
 10→}
 11→
 12→const SourceOfTruthModal: React.FC<Props> = ({ isOpen, onClose, project }) => {
 13→  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
 14→  const [format, setFormat] = useState<'txt' | 'json'>('txt');
 15→  const [copied, setCopied] = useState(false);
 16→  const [data, setData] = useState<SourceOfTruthData>({
 17→    description: '',
 18→    type: 'SaaS B2B',
 19→    founded: new Date().getFullYear().toString(),
 20→    location: 'Paris, France',
 21→    services: [{ name: 'AEO Score Analysis', description: 'Analyse automatique de la qualité de votre contenu pour les systèmes IA.', category: 'Analytics' }],
 22→    faqs: [{ question: "Qu'est-ce que l'AEO ?", answer: "L'AEO est l'optimisation de contenu pour les moteurs de réponse IA." }]
 23→  });
 24→
 25→  useEffect(() => {
 26→    if (project) {
 27→      setData(prev => ({
 28→        ...prev,
 29→        description: `Plateforme d'optimisation pour les moteurs de réponse IA (AEO). Analyse et améliore la visibilité de ${project.name} auprès des assistants IA.`,
 30→      }));
 31→    }
 32→  }, [project]);
 33→
 34→  if (!isOpen || !project) return null;
 35→
 36→  const handleServiceChange = (idx: number, field: string, value: string) => {
 37→    const newServices = [...data.services];
 38→    (newServices[idx] as any)[field] = value;
 39→    setData({ ...data, services: newServices });
 40→  };
 41→
 42→  const handleFaqChange = (idx: number, field: string, value: string) => {
 43→    const newFaqs = [...data.faqs];
 44→    (newFaqs[idx] as any)[field] = value;
 45→    setData({ ...data, faqs: newFaqs });
 46→  };
 47→
 48→  const addService = () => setData({ ...data, services: [...data.services, { name: '', description: '', category: '' }] });
 49→  const removeService = (idx: number) => setData({ ...data, services: data.services.filter((_, i) => i !== idx) });
 50→
 51→  const addFaq = () => setData({ ...data, faqs: [...data.faqs, { question: '', answer: '' }] });
 52→  const removeFaq = (idx: number) => setData({ ...data, faqs: data.faqs.filter((_, i) => i !== idx) });
 53→
 54→  const generateContent = () => {
 55→    const projectInfo = { name: project.name, domain: project.domain };
 56→    return format === 'json' 
 57→      ? LLM_TRUTH_TEMPLATES.json(projectInfo, data)
 58→      : LLM_TRUTH_TEMPLATES.txt(projectInfo, data);
 59→  };
 60→
 61→  const handleCopy = () => {
 62→    navigator.clipboard.writeText(generateContent());
 63→    setCopied(true);
 64→    setTimeout(() => setCopied(false), 2000);
 65→  };
 66→
 67→  const handleDownload = () => {
 68→    const blob = new Blob([generateContent()], { type: format === 'json' ? 'application/json' : 'text/plain' });
 69→    const url = URL.createObjectURL(blob);
 70→    const a = document.createElement('a');
 71→    a.href = url;
 72→    a.download = `llm.${format}`;
 73→    document.body.appendChild(a);
 74→    a.click();
 75→    document.body.removeChild(a);
 76→    URL.revokeObjectURL(url);
 77→  };
 78→
 79→  return (
 80→    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
 81→      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose}></div>
 82→      <div className="relative bg-[#0f1115] border border-white/10 rounded-2xl w-full max-w-5xl h-[85vh] flex flex-col shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
 83→        
 84→        {/* Header */}
 85→        <div className="p-6 border-b border-white/10 flex items-center justify-between bg-white/5">
 86→          <div className="flex items-center gap-3">
 87→            <div className="w-10 h-10 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400 border border-purple-500/30">
 88→              <FileText size={20} />
 89→            </div>
 90→            <div>
 91→              <h3 className="text-lg font-serif font-bold text-white">LLM Source of Truth</h3>
 92→              <p className="text-xs text-gray-400">Générez le fichier de référence pour les IA (llm.txt / llm.json)</p>
 93→            </div>
 94→          </div>
 95→          <div className="flex items-center gap-2">
 96→            <div className="flex bg-black/40 rounded-lg p-1 mr-4 border border-white/10">
 97→              <button onClick={() => setActiveTab('edit')} className={`px-4 py-1.5 rounded-md text-sm transition-all ${activeTab === 'edit' ? 'bg-white/10 text-white' : 'text-gray-500 hover:text-gray-300'}`}>Éditer</button>
 98→              <button onClick={() => setActiveTab('preview')} className={`px-4 py-1.5 rounded-md text-sm transition-all ${activeTab === 'preview' ? 'bg-purple-500/20 text-purple-300' : 'text-gray-500 hover:text-gray-300'}`}>Aperçu</button>
 99→            </div>
100→            <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-lg transition-colors text-gray-400 hover:text-white"><X size={20} /></button>
101→          </div>
102→        </div>
103→
104→        {/* Content */}
105→        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#0a0a0f]">
106→          {activeTab === 'edit' ? (
107→            <div className="p-8 max-w-4xl mx-auto space-y-8">
108→              
109→              {/* Identity Section */}
110→              <section className="space-y-4">
111→                <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2">
112→                  <Building2 size={16} /> Identité Organisation
113→                </h4>
114→                <div className="grid grid-cols-2 gap-4">
115→                  <div className="col-span-2">
116→                    <label className="block text-xs text-gray-400 mb-1">Description courte (Context Window friendly)</label>
117→                    <textarea 
118→                      value={data.description}
119→                      onChange={(e) => setData({...data, description: e.target.value})}
120→                      className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-purple-500/50 outline-none h-24 text-sm"
121→                      placeholder="Décrivez votre organisation en 2-3 phrases factuelles..."
122→                    />
123→                  </div>
124→                  <div>
125→                    <label className="block text-xs text-gray-400 mb-1">Type</label>
126→                    <input 
127→                      type="text" value={data.type}
128→                      onChange={(e) => setData({...data, type: e.target.value})}
129→                      className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white text-sm" 
130→                    />
131→                  </div>
132→                  <div>
133→                    <label className="block text-xs text-gray-400 mb-1">Année création</label>
134→                    <div className="relative">
135→                      <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={14} />
136→                      <input 
