46→        )}
47→      </div>
48→      
49→      {!simple && isExpanded && (
50→        <div className="px-4 pb-4 border-t border-white/5 bg-black/20">
51→          <div className="mt-3 space-y-3">
52→            {category.items.map((item, idx) => (
53→              <div key={idx} className="flex items-start gap-3 text-sm p-2 rounded hover:bg-purple-500/5">
